{
    "level": "B1",
    "intro": "W tym temacie nauczysz się <strong>stanu strony biernej w czasach kluczowych</strong>: ciągłego, doskonałego i przyszłego.",
    "rules": [
        {
            "label": "Ciągły",
            "color": "emerald",
            "text": "<strong>być + być + V3</strong> — działanie w toku:",
            "example": "The house is being painted."
        },
        {
            "label": "Doskonały",
            "color": "blue",
            "text": "<strong>był/był + V3</strong> - zakończona akcja:",
            "example": "The letter has been sent."
        },
        {
            "label": "Przyszły",
            "color": "rose",
            "text": "<strong>będzie + będzie + V3</strong> — przyszłe działania:",
            "example": "The work will be done."
        }
    ]
}

{
    "title": "1. Czas teraźniejszy ciągły bierny — jest wykonywany",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Wzór: <strong>jestem/jest/jestem + istota + imiesłów czasu przeszłego (V3)</strong>",
            "examples": [
                {
                    "en": "The house is being painted right now.",
                    "ua": "Dom jest właśnie malowany."
                },
                {
                    "en": "The documents are being prepared at the moment.",
                    "ua": "Dokumenty są w tej chwili przygotowywane."
                },
                {
                    "en": "I am being interviewed for a new position.",
                    "ua": "Jestem w trakcie rozmowy kwalifikacyjnej na nowe stanowisko."
                }
            ]
        },
        {
            "label": "Używanie",
            "color": "sky",
            "description": "Akcja <strong>dzieje się teraz</strong> i jest w toku. Długotrwałe działanie w stanie pasywnym.",
            "examples": [
                {
                    "en": "The road is being repaired this week.",
                    "ua": "W tym tygodniu droga będzie naprawiana."
                },
                {
                    "en": "New software is being installed on all computers.",
                    "ua": "Na wszystkich komputerach instalowane jest nowe oprogramowanie."
                }
            ]
        },
        {
            "label": "Zastrzeżenia i pytania",
            "color": "amber",
            "description": "Neg: <strong>jestem/jest/jestem + nie + bycie + V3</strong>. P: <strong>Jestem/jest/jestem + S + istota + V3?</strong>",
            "examples": [
                {
                    "en": "The house is not being painted today.",
                    "ua": "Dziś dom nie jest malowany."
                },
                {
                    "en": "Is the project being worked on?",
                    "ua": "Pracujesz nad projektem?"
                }
            ]
        }
    ]
}

{
    "title": "2. Past Continuous Passive — było robione",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Wzór: <strong>był/był + byt + imiesłów czasu przeszłego (V3)</strong>",
            "examples": [
                {
                    "en": "The car was being repaired when I arrived.",
                    "ua": "Kiedy przyjechałem, samochód był w naprawie."
                },
                {
                    "en": "The rooms were being cleaned all morning.",
                    "ua": "Pokoje były sprzątane przez cały ranek."
                },
                {
                    "en": "I was being examined by the doctor.",
                    "ua": "Lekarz mnie zbadał."
                }
            ]
        },
        {
            "label": "Używanie",
            "color": "sky",
            "description": "Akcja <strong>kontynuowała w przeszłości</strong> w pewnym momencie. Proces, który miał miejsce.",
            "examples": [
                {
                    "en": "While I was waiting, my application was being processed.",
                    "ua": "Kiedy czekałem, mój wniosek był przetwarzany."
                },
                {
                    "en": "The building was being constructed last year.",
                    "ua": "Budynek powstał w ubiegłym roku."
                }
            ]
        },
        {
            "label": "Zastrzeżenia i pytania",
            "color": "amber",
            "description": "Neg: <strong>był/był + nie + był + V3</strong>. P: <strong>Było/było + S + jest + V3?</strong>",
            "examples": [
                {
                    "en": "The issue was not being discussed then.",
                    "ua": "Wtedy ta kwestia nie była poruszana."
                },
                {
                    "en": "Were the emails being sent?",
                    "ua": "Wysłano e-maile?"
                }
            ]
        }
    ]
}

{
    "title": "3. Present Perfect Passive — zostało zrobione",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Wzór: <strong>był/był + imiesłów czasu przeszłego (V3)</strong>",
            "examples": [
                {
                    "en": "The project has been completed successfully.",
                    "ua": "Projekt został pomyślnie ukończony."
                },
                {
                    "en": "All the tickets have been sold already.",
                    "ua": "Wszystkie bilety zostały już sprzedane."
                },
                {
                    "en": "I have been promoted to manager!",
                    "ua": "Awansowałem na menadżera!"
                }
            ]
        },
        {
            "label": "Używanie",
            "color": "sky",
            "description": "Akcja jest <strong>zakończona</strong> i teraz ważny jest wynik. Połączenie z teraźniejszością.",
            "examples": [
                {
                    "en": "The report has just been submitted.",
                    "ua": "Właśnie przesłano raport."
                },
                {
                    "en": "The files have already been deleted.",
                    "ua": "Pliki zostały już usunięte."
                },
                {
                    "en": "The work has been done perfectly.",
                    "ua": "Praca wykonana perfekcyjnie."
                }
            ]
        },
        {
            "label": "Znaczniki czasu",
            "color": "amber",
            "description": "Typowe słowa: <strong>tylko, już, jeszcze, niedawno, kiedykolwiek, nigdy, odkąd, na</strong>",
            "examples": [
                {
                    "en": "The email has not been sent yet.",
                    "ua": "E-mail nie został jeszcze wysłany."
                },
                {
                    "en": "Have you ever been interviewed?",
                    "ua": "Czy kiedykolwiek udzielałeś wywiadu?"
                }
            ]
        }
    ]
}

{
    "title": "4. Past Perfect Passive — zostało zrobione",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Wzór: <strong>miał + był + imiesłów czasu przeszłego (V3)</strong>",
            "examples": [
                {
                    "en": "The work had been finished before the deadline.",
                    "ua": "Prace zakończono przed terminem."
                },
                {
                    "en": "The tickets had been sold out before we arrived.",
                    "ua": "Bilety zostały wyprzedane przed naszym przyjazdem."
                },
                {
                    "en": "The documents had been signed earlier.",
                    "ua": "Dokumenty zostały podpisane wcześniej."
                }
            ]
        },
        {
            "label": "Używanie",
            "color": "sky",
            "description": "Czynność została ukończona <strong>przed inną przeszłą czynnością</strong> lub momentem.",
            "examples": [
                {
                    "en": "By the time I got there, the problem had been solved.",
                    "ua": "W momencie mojego przyjazdu problem był już rozwiązany."
                },
                {
                    "en": "The email had been deleted before I could read it.",
                    "ua": "E-mail został usunięty, zanim zdążyłem go przeczytać."
                }
            ]
        },
        {
            "label": "Zastrzeżenia i pytania",
            "color": "amber",
            "description": "Neg: <strong>miał + nie + był + V3</strong>. P: <strong>Czy + S + było + V3?</strong>",
            "examples": [
                {
                    "en": "The work had not been completed by then.",
                    "ua": "Do tego czasu prace nie zostały ukończone."
                },
                {
                    "en": "Had the letter been sent?",
                    "ua": "Czy list został wysłany?"
                }
            ]
        }
    ]
}

{
    "title": "5. Przyszły prosty pasywny — zostanie wykonany",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Wzór: <strong>will + be + imiesłów czasu przeszłego (V3)</strong>",
            "examples": [
                {
                    "en": "The results will be announced tomorrow.",
                    "ua": "Wyniki zostaną ogłoszone jutro."
                },
                {
                    "en": "The meeting will be held next Monday.",
                    "ua": "Spotkanie odbędzie się w najbliższy poniedziałek."
                },
                {
                    "en": "You will be contacted soon.",
                    "ua": "Wkrótce się z Tobą skontaktujemy."
                }
            ]
        },
        {
            "label": "Używanie",
            "color": "sky",
            "description": "Akcja <strong>będzie miała miejsce w przyszłości</strong>. Plan, forecast, promise in the passive voice.",
            "examples": [
                {
                    "en": "The work will be done by Friday.",
                    "ua": "Prace zostaną wykonane do piątku."
                },
                {
                    "en": "A new office will be opened next year.",
                    "ua": "Nowe biuro zostanie otwarte w przyszłym roku."
                }
            ]
        },
        {
            "label": "Zastrzeżenia i pytania",
            "color": "amber",
            "description": "Negatywny: <strong>nie będzie (nie będzie) + będzie + V3</strong>. P: <strong>Czy + S + będzie + V3?</strong>",
            "examples": [
                {
                    "en": "The project will not be finished on time.",
                    "ua": "Projekt nie zostanie ukończony w terminie."
                },
                {
                    "en": "Will the report be ready by Friday?",
                    "ua": "Czy raport będzie gotowy do piątku?"
                }
            ]
        }
    ]
}

{
    "title": "6. Future Perfect Passive — zostanie wykonane",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Wzór: <strong>będzie + był + imiesłów czasu przeszłego (V3)</strong>. Rzadko używany.",
            "examples": [
                {
                    "en": "The work will have been completed by next week.",
                    "ua": "Prace zakończą się w przyszłym tygodniu."
                },
                {
                    "en": "By tomorrow, the report will have been submitted.",
                    "ua": "Raport zostanie złożony najpóźniej jutro."
                }
            ]
        },
        {
            "label": "Używanie",
            "color": "sky",
            "description": "Akcja <strong>zostanie zakończona w pewnym momencie w przyszłości</strong>. Jest to rzadkie.",
            "examples": [
                {
                    "en": "By 6 PM, all emails will have been sent.",
                    "ua": "Wszystkie listy zostaną wysłane do godziny 18:00."
                }
            ]
        }
    ]
}

{
    "title": "7. Tabela podsumowująca wszystkie czasy w stronie biernej",
    "intro": "Struktury stanu biernego we wszystkich czasach głównych:",
    "rows": [
        {
            "en": "Present Simple",
            "ua": "jestem/jest/są + V3",
            "note": "The letter is written."
        },
        {
            "en": "Past Simple",
            "ua": "był/był + V3",
            "note": "The letter was written."
        },
        {
            "en": "Present Continuous",
            "ua": "jestem/jest/są + bycie + V3",
            "note": "The letter is being written."
        },
        {
            "en": "Past Continuous",
            "ua": "był/był + bycie + V3",
            "note": "The letter was being written."
        },
        {
            "en": "Present Perfect",
            "ua": "ma/były + były + V3",
            "note": "The letter has been written."
        },
        {
            "en": "Past Perfect",
            "ua": "miał + był + V3",
            "note": "The letter had been written."
        },
        {
            "en": "Future Simple",
            "ua": "będzie + będzie + V3",
            "note": "The letter will be written."
        },
        {
            "en": "Future Perfect",
            "ua": "będzie + było + V3",
            "note": "The letter will have been written."
        }
    ]
}

{
    "title": "8. Które czasy nie mają strony biernej?",
    "sections": [
        {
            "label": "Nie ma ciągłej doskonałości",
            "color": "rose",
            "description": "Czasy <strong>Present Perfect Continuous</strong> i inne Perfect Continuous nie mają formy biernej.",
            "examples": [
                {
                    "en": "❌ The letter has been being written. (немає такої форми)",
                    "ua": "Zamiast tego używają strony biernej Present Perfect: został napisany"
                }
            ]
        },
        {
            "label": "Rzadko: Przyszły ciągły",
            "color": "amber",
            "description": "<strong>Future Continuous Passive</strong> teoretycznie istnieje, ale jest bardzo rzadko używany.",
            "examples": [
                {
                    "en": "The house will be being painted. (рідко)",
                    "ua": "Lepiej jest użyć: Dom zostanie pomalowany."
                }
            ]
        }
    ]
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zamieszanie z byciem w trybie ciągłym.",
            "wrong": "The house is painted now.",
            "right": "✅ The house is being painted now."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Skip był w Perfect.",
            "wrong": "The work has completed.",
            "right": "✅ The work has been completed."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zła kolejność w przyszłości.",
            "wrong": "It be will done.",
            "right": "✅ It will be done."
        }
    ]
}
